// src/pages/Login.jsx
// Formulario de login y registro. Guarda el token en AuthContext.

import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { loginUser, registerUser } from '../api/authApi'
import { useAuth } from '../context/AuthContext'
import Button from '../components/common/Button'
import styles from './Login.module.css'

export default function Login() {
  const [mode,    setMode]    = useState('login') // 'login' | 'register'
  const [form,    setForm]    = useState({ name: '', email: '', password: '' })
  const [error,   setError]   = useState(null)
  const [loading, setLoading] = useState(false)
  const { login } = useAuth()
  const navigate  = useNavigate()

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value })
    setError(null)
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)
    setError(null)
    try {
      const fn  = mode === 'login' ? loginUser : registerUser
      const res = await fn(form)
      login(res.user, res.token)
      navigate('/')
    } catch (err) {
      setError(err.response?.data?.error || 'Error al procesar la solicitud')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className={styles.page}>
      <div className={styles.card}>
        <div className={styles.header}>
          <span className={styles.logo}>💰</span>
          <h1>FinanzasApp</h1>
          <p>{mode === 'login' ? 'Inicia sesión en tu cuenta' : 'Crea tu cuenta gratis'}</p>
        </div>

        <form onSubmit={handleSubmit} className={styles.form}>
          {mode === 'register' && (
            <div className="form-group">
              <label htmlFor="name">Nombre</label>
              <input name="name" id="name" placeholder="Tu nombre" value={form.name} onChange={handleChange} required />
            </div>
          )}
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input name="email" id="email" type="email" placeholder="tu@email.com" value={form.email} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="password">Contraseña</label>
            <input name="password" id="password" type="password" placeholder="••••••" value={form.password} onChange={handleChange} required minLength={6} />
          </div>

          {error && <p className="msg msg--error">{error}</p>}

          <Button type="submit" fullWidth loading={loading}>
            {mode === 'login' ? 'Iniciar sesión' : 'Crear cuenta'}
          </Button>
        </form>

        <p className={styles.toggle}>
          {mode === 'login' ? '¿No tienes cuenta?' : '¿Ya tienes cuenta?'}{' '}
          <button onClick={() => { setMode(mode === 'login' ? 'register' : 'login'); setError(null) }}>
            {mode === 'login' ? 'Regístrate' : 'Inicia sesión'}
          </button>
        </p>
      </div>
    </div>
  )
}
